; item_text.asm — item-use message command streams (items layer, Stage 5).
;
; The generated streams live in .data (linker rule: embedded data goes in .data,
; never an unmapped section — see docs/assembly.md). assets/item_text.inc carries
; its own `section .data` + `global` per label, so this file is just the include
; shell, mirroring src/data/item_data.asm.
;
; Generated by tools/generators/gen_item_text.py (pret engine/items/item_effects.asm +
; engine/menus/party_menu.asm text wrappers, text_far flattened). DO NOT hand-edit
; the .inc.
;
; Build: nasm -f coff -I include/ -I . -o item_text.o item_text.asm

bits 32

%include "assets/item_text.inc"
